import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'

// PATCH /api/clients/[id]  — update a client
// DELETE /api/clients/[id] — delete a client

export async function PATCH(req: NextRequest, { params }: { params: { id: string } }) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const body = await req.json()
  const allowed = [
    'name', 'company', 'email', 'phone', 'role', 'status', 'notes', 'tags', 'total_billed',
    'project_title', 'project_description', 'project_deadline', 'progress_percent', 'milestones'
  ]
  const updates = Object.fromEntries(
    Object.entries(body).filter(([k]) => allowed.includes(k))
  )

  const { data, error } = await (supabase as any)
    .from('clients')
    .update(updates)
    .eq('id', params.id)
    .eq('user_id', user.id)
    .select()
    .single()

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json(data)
}

export async function DELETE(_req: NextRequest, { params }: { params: { id: string } }) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const { error } = await (supabase as any)
    .from('clients')
    .delete()
    .eq('id', params.id)
    .eq('user_id', user.id)

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return new NextResponse(null, { status: 204 })
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'

// GET  /api/clients  —  list all clients for the current user
// POST /api/clients  —  create a new client
export async function GET() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const { data, error } = await (supabase as any)
    .from('clients')
    .select('*')
    .eq('user_id', user.id)
    .order('created_at', { ascending: false })

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json(data)
}

export async function POST(req: NextRequest) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const body = await req.json()
  const { 
    name, company, email, phone, role, status, notes, tags,
    project_title, project_description, project_deadline, progress_percent, milestones
  } = body

  if (!name?.trim()) {
    return NextResponse.json({ error: 'Name is required' }, { status: 400 })
  }

  const { data, error } = await (supabase as any)
    .from('clients')
    .insert({
      user_id: user.id,
      name: name.trim(),
      company: company?.trim() || null,
      email: email?.trim() || null,
      phone: phone?.trim() || null,
      role: role?.trim() || null,
      status: status || 'active',
      notes: notes?.trim() || null,
      tags: tags?.length ? tags : null,
      // Project tracking fields
      project_title: project_title?.trim() || null,
      project_description: project_description?.trim() || null,
      project_deadline: project_deadline || null,
      progress_percent: progress_percent ?? 0,
      milestones: milestones || [],
    })
    .select()
    .single()

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json(data, { status: 201 })
}

import { NextRequest, NextResponse } from "next/server";
import { renderToBuffer } from "@react-pdf/renderer";
import type { DocumentProps } from "@react-pdf/renderer";
import { createClient } from "@/lib/supabase/server";
import { ContractPDFTemplate } from "@/lib/pdf/contract-templates";
import type { Database } from "@/lib/supabase/types";
import React, { type ReactElement } from "react";

type ContractRow = Database["public"]["Tables"]["contracts"]["Row"];
type UserRow = Database["public"]["Tables"]["users"]["Row"];

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const supabase = await createClient();

    // 1. Auth check
    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();

    if (authError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // 2. Fetch contract
    const { data: contract, error: fetchError } = await supabase
      .from("contracts")
      .select("*")
      .eq("id", id)
      .eq("user_id", user.id)
      .single() as { data: ContractRow | null; error: unknown };

    if (fetchError || !contract) {
      return NextResponse.json(
        { error: "Contract not found or access denied" },
        { status: 404 }
      );
    }

    // 3. Return existing PDF if already generated
    if (contract.pdf_url) {
      return NextResponse.json({ pdf_url: contract.pdf_url });
    }

    // 4. Fetch User Details for "Freelancer Name"
    const { data: seller } = await supabase
      .from("users")
      .select("name")
      .eq("id", user.id)
      .single() as { data: Pick<UserRow, "name"> | null; error: unknown };

    const freelancerName = seller?.name || user.email || "Freelancer";

    // 5. Parse Fields JSON
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const fields = contract.fields_json as any;

    // 6. Generate PDF Buffer
    const pdfBuffer = await renderToBuffer(
      React.createElement(ContractPDFTemplate, {
        type: contract.template_type,
        freelancerName,
        clientName: fields.clientName,
        effectiveDate: fields.effectiveDate,
        governingLaw: fields.governingLaw,
        projectScope: fields.projectScope,
        compensation: fields.compensation,
        duration: fields.duration,
      }) as ReactElement<DocumentProps>
    );

    // 7. Upload to Supabase Storage
    const filename = `${user.id}/contracts/${contract.template_type}-${Date.now()}.pdf`;

    const { error: uploadError } = await supabase.storage
      .from("documents") // Reusing the documents bucket
      .upload(filename, pdfBuffer, {
        contentType: "application/pdf",
        upsert: false,
      });

    if (uploadError) {
      console.error("[contracts/pdf] Upload error:", uploadError);
      return NextResponse.json(
        { error: "Failed to upload PDF", details: uploadError.message },
        { status: 500 }
      );
    }

    // 8. Sign URL
    const { data: signedData, error: signError } = await supabase.storage
      .from("documents")
      .createSignedUrl(filename, 3600);

    const pdfUrl = signedData?.signedUrl ?? filename;

    // 9. Patch Contract with pdf_url
    await supabase
      .from("contracts")
      .update({ pdf_url: pdfUrl } as never)
      .eq("id", contract.id)
      .eq("user_id", user.id);

    return NextResponse.json({ pdf_url: pdfUrl });
  } catch (err) {
    console.error("[contracts/pdf] Unexpected error:", err);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { z } from "zod";
import type { Database } from "@/lib/supabase/types";

type TemplateType = "nda" | "sow" | "retainer" | string;

const createContractSchema = z.object({
  template_type: z.enum(["nda", "sow", "retainer"] as const),
  fields_json: z.object({
    clientName: z.string().min(2, "Client Name must be at least 2 characters"),
    effectiveDate: z.string().min(10, "Effective date is required"),
    governingLaw: z.string().optional(),
    projectScope: z.string().optional(),
    compensation: z.string().optional(),
    duration: z.string().optional(),
  }),
});

export async function POST(req: NextRequest) {
  try {
    const supabase = await createClient();

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();

    if (authError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await req.json();
    const parsed = createContractSchema.safeParse(body);

    if (!parsed.success) {
      return NextResponse.json(
        { error: "Validation failed", details: parsed.error.format() },
        { status: 400 }
      );
    }

    const { template_type, fields_json } = parsed.data;

    const { data: contract, error: dbError } = await supabase
      .from("contracts")
      .insert({
        user_id: user.id,
        template_type: template_type as TemplateType,
        fields_json: fields_json as any, // Json type bypass
      } as any)
      .select()
      .single();

    if (dbError) {
      console.error("[contracts/POST] DB insert error:", dbError);
      return NextResponse.json(
        { error: "Failed to create contract" },
        { status: 500 }
      );
    }

    return NextResponse.json({ data: contract }, { status: 201 });
  } catch (err) {
    console.error("[contracts/POST] Unexpected error:", err);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

export async function GET() {
  try {
    const supabase = await createClient();

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();

    if (authError || !user) {
