import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function GET() {
  try {
    const supabase = await createClient();

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();

    if (authError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // 1. Fetch user profile
    const { data: profile } = await supabase
      .from("users")
      .select("*")
      .eq("id", user.id)
      .single() as { data: any; error: any };

    // 2. Fetch current month's invoices
    const startOfMonth = new Date();
    startOfMonth.setDate(1);
    startOfMonth.setHours(0, 0, 0, 0);

    const { data: recentInvoices } = await supabase
      .from("invoices")
      .select("id, type")
      .eq("user_id", user.id)
      .gte("created_at", startOfMonth.toISOString());

    const invoicesThisMonth = recentInvoices?.length || 0;

    // 3. Check for pending e-FIRAs
    //   An export invoice without a corresponding 'efira' document
    const { data: exportInvoicesRaw } = await supabase
      .from("invoices")
      .select("id")
      .eq("user_id", user.id)
      .eq("type", "export");

    const { data: efiraDocsRaw } = await supabase
      .from("documents")
      .select("invoice_id")
      .eq("user_id", user.id)
      .eq("doc_type", "efira");

    const exportInvoices = (exportInvoicesRaw as any[]) || [];
    const efiraDocs = (efiraDocsRaw as any[]) || [];

    const efiraInvoiceIds = new Set(efiraDocs.map((d) => d.invoice_id));
    const pendingEfiras = exportInvoices.filter(
      (inv) => !efiraInvoiceIds.has(inv.id)
    ).length;

    // 4. Calculate Compliance Health Score (0 - 100)
    let score = 100;

    // LUT active gives points if they have export turnover
    if (!profile?.lut_filed && exportInvoices?.length) {
      score -= 30; // High penalty for exporting without LUT
    }

    // Pending e-FIRAs drop the score
    if (pendingEfiras > 0) {
      score -= pendingEfiras * 10;
    }

    // No GSTIN setup drops the score
    if (!profile?.gstin) {
      score -= 20;
    }

    score = Math.max(0, score); // Floor at 0

    return NextResponse.json({
      data: {
        score,
        invoicesThisMonth,
        planTier: profile?.plan_tier || "free",
        lutFiled: profile?.lut_filed || false,
        pendingEfiras,
        hasGstin: !!profile?.gstin,
      },
    });
  } catch (err) {
    console.error("[stats/GET] Unexpected error:", err);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import type { Database } from "@/lib/supabase/types";

type InvoiceRow = Database["public"]["Tables"]["invoices"]["Row"];
type DocumentRow = Database["public"]["Tables"]["documents"]["Row"];

export type EfiraStatusResponse = InvoiceRow & {
  efira_document: DocumentRow | null;
};

// ── GET /api/efira ─────────────────────────────────────────────────────────

export async function GET() {
  try {
    const supabase = await createClient();

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();

    if (authError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Fetch all export invoices for the user
    const { data: exportInvoices, error: invError } = await supabase
      .from("invoices")
      .select("*")
      .eq("user_id", user.id)
      .eq("type", "export")
      .order("created_at", { ascending: false });

    if (invError) {
      return NextResponse.json({ error: invError.message }, { status: 500 });
    }

    // Fetch all e-FIRA documents for the user
    const { data: efiraDocs, error: docError } = await supabase
      .from("documents")
      .select("*")
      .eq("user_id", user.id)
      .eq("doc_type", "efira");

    if (docError) {
      return NextResponse.json({ error: docError.message }, { status: 500 });
    }

    // Map documents to their invoices
    const invoicesList = (exportInvoices as unknown as InvoiceRow[]) || [];
    const docsList = (efiraDocs as unknown as DocumentRow[]) || [];

    const mapped: EfiraStatusResponse[] = invoicesList.map((inv) => {
      const doc = docsList.find((d) => d.invoice_id === inv.id) || null;
      return { ...inv, efira_document: doc };
    });

    return NextResponse.json({ data: mapped });
  } catch (err) {
    console.error("[efira/GET] Unexpected error:", err);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ── POST /api/efira ─────────────────────────────────────────────────────────

export async function POST(req: NextRequest) {
  try {
    const supabase = await createClient();

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();

    if (authError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Parse formData (multipart/form-data)
    const formData = await req.formData();
    const invoiceId = formData.get("invoiceId") as string;
    const file = formData.get("file") as File;

    if (!invoiceId || !file) {
      return NextResponse.json(
        { error: "Missing invoiceId or file" },
        { status: 400 }
      );
    }

    if (file.type !== "application/pdf") {
      return NextResponse.json(
        { error: "Only PDF files are allowed for e-FIRA" },
        { status: 400 }
      );
    }

    // Verify invoice belongs to user and is an export
    const { data: invoice } = await supabase
      .from("invoices")
      .select("id")
      .eq("id", invoiceId)
      .eq("user_id", user.id)
      .eq("type", "export")
      .single();

    if (!invoice) {
      return NextResponse.json(
        { error: "Invalid invoice or unauthorized" },
        { status: 404 }
      );
    }

    // Check if e-FIRA already exists
    const { data: existingDoc } = await supabase
      .from("documents")
      .select("id")
      .eq("invoice_id", invoiceId)
      .eq("doc_type", "efira")
      .maybeSingle();

    if (existingDoc) {
      return NextResponse.json(
        { error: "e-FIRA already uploaded for this invoice" },
        { status: 409 }
      );
    }

    // Upload to Storage
    const ext = file.name.split(".").pop();
    const filename = `${user.id}/efira/${invoiceId}-${Date.now()}.${ext}`;

    const { error: uploadError } = await supabase.storage
      .from("documents")
      .upload(filename, file, {
        contentType: file.type,
        upsert: false,
      });

    if (uploadError) {
      console.error("[efira/POST] Storage error:", uploadError);
      return NextResponse.json(
        { error: "Failed to upload file to storage" },
        { status: 500 }
      );
    }

    // Get public URL (documents bucket is private, but we use a signed URL strategy later, 
    // or store the path and fetch signed URLs on the fly. We'll store the path.)
    const { data: signedData } = await supabase.storage
      .from("documents")
      .createSignedUrl(filename, 3600);

    const fileUrl = signedData?.signedUrl ?? filename;

    // Insert to DB
    const { data: document, error: dbError } = await supabase
      .from("documents")
      .insert({
        user_id: user.id,
        invoice_id: invoiceId,
        doc_type: "efira",
        file_url: filename,
      } as any)
      .select()
      .single();

    if (dbError) {
      console.error("[efira/POST] DB insert error:", dbError);
      return NextResponse.json(
        { error: "Failed to record document in database" },
        { status: 500 }
      );
    }

    return NextResponse.json({ data: document }, { status: 201 });
  } catch (err) {
    console.error("[efira/POST] Unexpected error:", err);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

